<script setup lang="ts">
import{computed,nextTick,onBeforeUnmount,onMounted,ref,watch}from"vue";import{useRoute}from"vue-router";import{Search,ChevronDown,LoaderCircle,MapPin}from"lucide-vue-next";import{api,type Department,type Doctor,type Hospital}from"../api";import PageHeader from"../components/PageHeader.vue";import DoctorCard from"../components/DoctorCard.vue";
const keyword=ref(String(useRoute().query.keyword??"")),doctors=ref<Doctor[]>([]),departments=ref<Department[]>([]),hospitals=ref<Hospital[]>([]),department=ref(""),province=ref(""),city=ref(""),page=ref(1),loading=ref(false),hasMore=ref(true),selector=ref<"region"|"department"|"disease"|null>(null),sentinel=ref<HTMLElement>();const diseases=["高血压","皮炎","儿童发热","眼底病","关节疼痛","睡眠障碍"];const departmentNames=computed(()=>[...new Set(departments.value.map(d=>d.name))]);const provinces=computed(()=>[...new Set(hospitals.value.map(h=>h.province))]);const cities=computed(()=>[...new Set(hospitals.value.filter(h=>!province.value||h.province===province.value).map(h=>h.city))]);let observer:IntersectionObserver|undefined,timer:number;
async function load(reset=false){if(loading.value||(!hasMore.value&&!reset))return;if(reset){page.value=1;doctors.value=[];hasMore.value=true}loading.value=true;try{const rows=await api.doctors({keyword:keyword.value,department:department.value,province:province.value,city:city.value,page:page.value,pageSize:20});doctors.value.push(...rows);hasMore.value=rows.length===20;if(hasMore.value)page.value++}finally{loading.value=false}}
function chooseRegion(p="",c=""){province.value=p;city.value=c;selector.value=null;void load(true)}function chooseDepartment(name=""){department.value=name;selector.value=null;void load(true)}function chooseDisease(name=""){keyword.value=name;selector.value=null;void load(true)}
onMounted(async()=>{[departments.value,hospitals.value]=await Promise.all([api.departments(),api.hospitals()]);await load(true);await nextTick();observer=new IntersectionObserver(e=>{if(e[0]?.isIntersecting)void load()},{rootMargin:"160px"});if(sentinel.value)observer.observe(sentinel.value)});onBeforeUnmount(()=>observer?.disconnect());watch(keyword,()=>{clearTimeout(timer);timer=window.setTimeout(()=>load(true),350)});
</script>
<template><main><PageHeader title="找医生"/><div class="search-box"><Search/><input v-model="keyword" placeholder="搜医院、医生、疾病"/></div><div class="filters"><button @click="selector='region'"><span>{{city||province||'全国省市'}}</span><ChevronDown/></button><button @click="selector='department'"><span>{{department||'全部科室'}}</span><ChevronDown/></button><button @click="selector='disease'"><span>{{diseases.includes(keyword)?keyword:'疾病'}}</span><ChevronDown/></button></div><section class="doctor-results"><DoctorCard v-for="d in doctors" :key="d.id" :doctor="d"/><div ref="sentinel" class="load-more"><LoaderCircle v-if="loading" class="spin"/><span v-if="loading">正在加载医生...</span><span v-else-if="!hasMore&&doctors.length">已经到底了</span><span v-else-if="!doctors.length">没有找到相关医生</span></div></section><div v-if="selector" class="overlay" @click.self="selector=null"><section class="sheet filter-sheet"><i class="handle"/><template v-if="selector==='region'"><h2><MapPin/>选择省市</h2><div class="option-grid"><button :class="{active:!province}" @click="chooseRegion()">全国</button><button v-for="p in provinces" :class="{active:province===p&&!city}" @click="province=p;city=''">{{p}}</button></div><h3 v-if="province">选择城市</h3><div class="option-grid"><button v-for="c in cities" :class="{active:city===c}" @click="chooseRegion(province,c)">{{c}}</button></div></template><template v-if="selector==='department'"><h2>选择科室</h2><div class="option-grid departments"><button :class="{active:!department}" @click="chooseDepartment()">全部科室</button><button v-for="d in departmentNames" :class="{active:department===d}" @click="chooseDepartment(d)">{{d}}</button></div></template><template v-if="selector==='disease'"><h2>选择常见疾病</h2><div class="option-grid"><button v-for="d in diseases" :class="{active:keyword===d}" @click="chooseDisease(d)">{{d}}</button></div></template></section></div></main></template>
